function db(k,v){
  if(v===undefined)return JSON.parse(localStorage.getItem(k)||'null');
  localStorage.setItem(k,JSON.stringify(v));
}
function dba(k){return db(k)||[];}
function g(id){return document.getElementById(id);}
function f2(n){return (parseFloat(n)||0).toFixed(2);}
function today(){return new Date().toISOString().slice(0,10);}
function nowStr(){return new Date().toLocaleString('es-MX');}
function toast(msg,dur=2800){
  const t=g('toast');t.textContent=msg;t.classList.add('show');
  setTimeout(()=>t.classList.remove('show'),dur);
}
function openModal(id){g(id).classList.add('open');}
function closeModal(id){g(id).classList.remove('open');}

if(!db('pp_v4_clean')){db('inventario',INIT_INV);db('pp_v3',true);}
